class VibratoChannelProcessor {
  constructor(frequency, depth) {
    this.frequency = frequency;
    this.depth = depth;
    this.phase = 0;
    this.totalSamples = 0;
  }

  processInt(int) {
    const vibratoValue = Math.sin(2 * Math.PI * this.frequency * this.totalSamples / 48000) * this.depth;
    this.totalSamples++;

    const pitchMultiplier = Math.pow(2, vibratoValue / 12.0);

    const newValue = int * pitchMultiplier;

    const clippedValue = Math.min(32767, Math.max(-32768, newValue));

    return clippedValue;
  }

  process(samples, extremum, bytes) {
    const endIndex = Math.floor(samples.length / bytes) * bytes;

    for (let sampleIndex = 0; sampleIndex < endIndex; sampleIndex += bytes) {
      const sample = samples.readInt16LE(sampleIndex);
      const processedSample = this.processInt(sample);
      samples.writeInt16LE(processedSample, sampleIndex);
    }

    return samples;
  }
}


class VibratoFilter extends Transform {
  constructor(channelCount, { frequency, depth }) {
    super();

    this.frequency = frequency;
    this.depth = depth;
    this.channels = [];

    for (let i = 0; i < channelCount; i++) {
      this.channels.push(new VibratoChannelProcessor(frequency, depth));
    }
  }

  process(input, extremum) {
    const result = input.map(({ data }) => {
      return this.channels.map((c) => c.process(data, extremum));
    });

    const channelLength = input[0].data.length;
    const processedData = Buffer.alloc(channelLength * 2 * result.length);

    for (let i = 0; i < channelLength; i += 2) {
      for (let j = 0; j < result.length; j++) {
        const channelData = result[j];
        processedData.writeInt16LE(channelData[i], i * result.length + j * 2);
      }
    }

    return processedData;
  }

  _transform(data, _encoding, callback) {
    const extremum = Math.pow(2, 16 - 1);
    const processedData = this.process([{ data }], extremum);

    console.log('Processed Data:', processedData);

    this.push(processedData);
    return callback();
  }
}


